// ============================================================
// Error Formatter
// Extracts useful info from the n8n error object
// ============================================================

const err = $input.item.json;

const workflowName = err.workflow?.name || 'Unknown Workflow';
const executionId  = err.execution?.id || 'N/A';
const lastNode     = err.execution?.lastNodeExecuted || 'Unknown Node';
const errorMsg     = err.execution?.error?.message || 'No error message';
const errorStack   = err.execution?.error?.stack || '';
const timestamp    = new Date().toISOString();

// Determine severity
let severity = 'WARNING';
if (errorMsg.toLowerCase().includes('rate limit')) severity = 'INFO';
if (errorMsg.toLowerCase().includes('unauthorized')) severity = 'CRITICAL';
if (errorMsg.toLowerCase().includes('quota')) severity = 'CRITICAL';

return [{
  json: {
    workflowName,
    executionId,
    lastNode,
    errorMsg,
    errorStack: errorStack.substring(0, 500),
    severity,
    timestamp
  }
}];

